# Drizzle Schema Definition

Drizzle schemas are TypeScript files that define your database structure. Each table is created with a dialect-specific function, columns are typed functions, and constraints are chained methods.

## PostgreSQL Schema

```typescript
import {
  pgTable, pgEnum, serial, integer, text, varchar,
  boolean, timestamp, uuid, jsonb, numeric, index, uniqueIndex
} from 'drizzle-orm/pg-core';

// Enum
export const roleEnum = pgEnum('role', ['user', 'admin', 'moderator']);

// Users table
export const users = pgTable('users', {
  id: serial('id').primaryKey(),
  name: text('name').notNull(),
  email: varchar('email', { length: 255 }).notNull().unique(),
  role: roleEnum('role').default('user'),
  bio: text('bio'),
  metadata: jsonb('metadata'),
  createdAt: timestamp('created_at').defaultNow().notNull(),
  updatedAt: timestamp('updated_at').defaultNow().notNull(),
}, (table) => [
  index('email_idx').on(table.email),
]);

// Posts table with foreign key
export const posts = pgTable('posts', {
  id: serial('id').primaryKey(),
  title: varchar('title', { length: 256 }).notNull(),
  content: text('content'),
  slug: varchar('slug', { length: 256 }).unique(),
  published: boolean('published').default(false),
  authorId: integer('author_id').references(() => users.id, { onDelete: 'cascade' }).notNull(),
  createdAt: timestamp('created_at').defaultNow().notNull(),
}, (table) => [
  index('author_idx').on(table.authorId),
  index('slug_idx').on(table.slug),
]);

// Tags — many-to-many via join table
export const tags = pgTable('tags', {
  id: serial('id').primaryKey(),
  name: varchar('name', { length: 64 }).notNull().unique(),
});

export const postsToTags = pgTable('posts_to_tags', {
  postId: integer('post_id').references(() => posts.id, { onDelete: 'cascade' }).notNull(),
  tagId: integer('tag_id').references(() => tags.id, { onDelete: 'cascade' }).notNull(),
}, (table) => [
  { pk: primaryKey({ columns: [table.postId, table.tagId] }) },
]);
```

## MySQL Schema

```typescript
import {
  mysqlTable, mysqlEnum, int, varchar, text,
  boolean, timestamp, serial, json, index
} from 'drizzle-orm/mysql-core';

export const users = mysqlTable('users', {
  id: serial('id').primaryKey(),
  name: varchar('name', { length: 256 }).notNull(),
  email: varchar('email', { length: 256 }).notNull().unique(),
  role: mysqlEnum('role', ['user', 'admin']).default('user'),
  createdAt: timestamp('created_at').defaultNow().notNull(),
});
```

## SQLite Schema

```typescript
import {
  sqliteTable, integer, text, index
} from 'drizzle-orm/sqlite-core';

export const users = sqliteTable('users', {
  id: integer('id').primaryKey({ autoIncrement: true }),
  name: text('name').notNull(),
  email: text('email').notNull().unique(),
  role: text('role').$type<'user' | 'admin'>().default('user'),
  createdAt: text('created_at').default(sql`(CURRENT_TIMESTAMP)`),
});
```

## Column Types by Dialect

| Type | PostgreSQL | MySQL | SQLite |
|------|-----------|-------|--------|
| Auto-increment ID | `serial()` | `serial()` / `int().autoincrement()` | `integer().primaryKey({ autoIncrement: true })` |
| Integer | `integer()` | `int()` | `integer()` |
| Text | `text()` | `text()` | `text()` |
| Varchar | `varchar({ length })` | `varchar({ length })` | N/A (use `text()`) |
| Boolean | `boolean()` | `boolean()` | `integer({ mode: 'boolean' })` |
| Timestamp | `timestamp()` | `timestamp()` | `text()` / `integer({ mode: 'timestamp' })` |
| UUID | `uuid()` | N/A | N/A |
| JSON | `json()` / `jsonb()` | `json()` | `text({ mode: 'json' })` |
| Numeric | `numeric()` / `decimal()` | `decimal()` | `real()` |
| BigInt | `bigint()` | `bigint()` | `blob({ mode: 'bigint' })` |

## Column Constraints

```typescript
// Primary key
id: serial('id').primaryKey()

// Generated identity (PostgreSQL)
id: integer('id').generatedAlwaysAsIdentity()

// Not null
name: text('name').notNull()

// Unique
email: varchar('email').unique()

// Default value
role: text('role').default('user')

// Default with function
slug: varchar('slug').$default(() => generateSlug())

// Default now (timestamps)
createdAt: timestamp('created_at').defaultNow()

// Foreign key
authorId: integer('author_id').references(() => users.id)

// Foreign key with actions
authorId: integer('author_id').references(() => users.id, {
  onDelete: 'cascade',
  onUpdate: 'cascade',
})

// Self-referencing
parentId: integer('parent_id').references((): AnyPgColumn => categories.id)
```

## Indexes and Composite Keys

```typescript
import { pgTable, integer, text, index, uniqueIndex, primaryKey } from 'drizzle-orm/pg-core';

export const posts = pgTable('posts', {
  id: serial('id').primaryKey(),
  title: text('title').notNull(),
  authorId: integer('author_id').notNull(),
  categoryId: integer('category_id'),
}, (table) => [
  index('author_idx').on(table.authorId),
  index('author_category_idx').on(table.authorId, table.categoryId),
  uniqueIndex('title_unique_idx').on(table.title),
]);

// Composite primary key (join tables)
export const postsToTags = pgTable('posts_to_tags', {
  postId: integer('post_id').notNull(),
  tagId: integer('tag_id').notNull(),
}, (table) => [
  primaryKey({ columns: [table.postId, table.tagId] }),
]);
```

## PostgreSQL Enums

```typescript
import { pgEnum } from 'drizzle-orm/pg-core';

export const statusEnum = pgEnum('status', ['draft', 'published', 'archived']);

export const posts = pgTable('posts', {
  status: statusEnum('status').default('draft'),
});
```

## Automatic camelCase to snake_case

```typescript
// In your drizzle instance — maps camelCase TS keys to snake_case DB columns
const db = drizzle({ connection: process.env.DATABASE_URL, casing: 'snake_case' });

// Now you write:
export const users = pgTable('users', {
  firstName: text(),    // maps to first_name in DB
  lastName: text(),     // maps to last_name in DB
  createdAt: timestamp() // maps to created_at in DB
});
```

## Reusable Column Helpers

```typescript
// src/db/columns.ts
import { timestamp } from 'drizzle-orm/pg-core';

export const timestamps = {
  createdAt: timestamp('created_at').defaultNow().notNull(),
  updatedAt: timestamp('updated_at').defaultNow().notNull(),
};

// src/db/schema.ts
import { timestamps } from './columns';

export const users = pgTable('users', {
  id: serial('id').primaryKey(),
  name: text('name').notNull(),
  ...timestamps,
});
```

## Schema Organization

Single file: `src/db/schema.ts` — good for small projects.

Multiple files:
```
src/db/schema/
  users.ts
  posts.ts
  tags.ts
  index.ts     # re-export all
```

Point [[drizzle/config]] at the directory: `schema: './src/db/schema'`.

## Type Inference

```typescript
// Infer select type (what you read from DB)
type User = typeof users.$inferSelect;

// Infer insert type (what you write to DB)
type NewUser = typeof users.$inferInsert;
```

## Environment Variables

| Variable | Purpose |
|----------|--------|
| `DATABASE_URL` | Used in drizzle.config.ts for drizzle-kit operations |
